import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { BehaviorSubject, Observable, of } from 'rxjs';
import { catchError, delay, finalize, map } from 'rxjs/operators';
import { BaseEntity } from './base-entity-interface';
import { Person } from './person-interface';
import { Planet } from './planet-interface';

@Injectable({ providedIn: 'root' })
export class MockDataService {
  private charactersLoader$ = new BehaviorSubject<boolean>(false);
  private planetsLoader$ = new BehaviorSubject<boolean>(false);

  private people$: Observable<Person[]> = this.loadAssets<Person>('assets/data/people.json');
  private planets$: Observable<Planet[]> = this.loadAssets<Planet>('assets/data/planets.json');

  constructor(private http: HttpClient) {}

  private loadAssets<T extends BaseEntity>(url: string): Observable<T[]> {
    return this.http.get<any[]>(url).pipe(
      map((arr) => arr.map((item) => ({ ...(item.fields ?? {}), pk: item.pk } as T))),
      catchError(() => of([] as T[]))
    );
  }

  getCharacters(searchTerm = ''): Observable<Person[]> {
    this.charactersLoader$.next(true);
    const term = searchTerm.trim().toLowerCase();

    return this.people$.pipe(
      map((list) => this.filterByName(list, term)),
      delay(250),
      finalize(() => this.charactersLoader$.next(false))
    );
  }

  getPlanets(searchTerm = ''): Observable<Planet[]> {
    this.planetsLoader$.next(true);
    const term = searchTerm.trim().toLowerCase();

    return this.planets$.pipe(
      map((list) => this.filterByName(list, term)),
      delay(250),
      finalize(() => this.planetsLoader$.next(false))
    );
  }

  getCharactersLoader(): Observable<boolean> {
    return this.charactersLoader$.asObservable();
  }

  getPlanetLoader(): Observable<boolean> {
    return this.planetsLoader$.asObservable();
  }

  private filterByName<T extends BaseEntity>(list: T[], term: string): T[] {
    return !term ? list : list.filter((item) => (item.name ?? '').toLowerCase().includes(term));
  }
}
